"""Unit tests for src/make_init.py."""import torchimport torch.nn as nnfrom src.model import GPT, GPTConfigfrom src.make_init import assert_hla_identity, is_hla_keydef test_is_hla_key():    assert is_hla_key("transformer.h.0.attn.W_phase_q")    assert is_hla_key("transformer.h.5.attn.W_gate_k.weight")    assert not is_hla_key("transformer.h.0.attn.c_attn.weight")    assert not is_hla_key("transformer.wte.weight")def test_assert_hla_identity_passes_on_fresh_model():    """Fresh GPT should have all HLA params at identity."""    config = GPTConfig(n_layer=2, n_head=4, n_embd=128)    model = GPT(config)    model.reset_hla_identity()    assert_hla_identity(model)  # should not raise